@mvantellingen 

It's possible to do a `prefetch`-like operation on the entire category tree.

```python
class AbstractCategory(MP_Node):

    @classmethod
    def get_annotated_list(cls, max_depth=None, parent=None):
        """
        Gets an annotated list from a branch by doing an in-order tree traversal over
        cls.dump_bulk()
        """

        if parent is None:
            roots = cls.get_root_nodes()
        else:
            roots = [parent]

        trees = [cls.dump_bulk(root) for root in roots]

        instances, infos = [], []

        def flatten(nodes, ancestors=()):
            for node in nodes:
                node['data']['id'] = node['data']['pk'] = node['id']

                instance = cls(**node['data'])

                ancestors_and_self = ancestors + (instance, )

                # Patch ancestors and self to do zero queries
                instance.get_ancestors_and_self = lambda: ancestors_and_self

                instances.append(instance)
                infos.append({
                    'level': len(ancestors),
                })

                if 'children' in node and (max_depth is None or len(ancestors_and_self) < max_depth):
                    flatten(node['children'], ancestors_and_self)

        for tree in trees:
            flatten(tree)

        # Rotate infos so we can compare first to last
        infos_rotated = infos[-1:] + infos[:-1]

        for left, right in zip(infos_rotated, infos):
            left['num_to_close'] = list(range(0, left['level'] - right['level']))
            left['has_children'] = right['level'] > left['level']

        return zip(instances, infos)
```

Using the data set you provided, this reduces the number of queries on the category detail page to 82.

You can patch the `ModelChoice` field in the dashboard similarly:

```python
# apps.dashboard.catalogue.forms
def get_patched_categories():
    def iterator_patch():
        for instance, __ in Category.get_annotated_list():
            yield instance
    categories = Category.objects.all()
    categories.iterator = iterator_patch
    return categories


class ProductCategoryForm(forms.ModelForm):

    category = forms.ModelChoiceField(queryset=get_patched_categories())

    class Meta:
        model = ProductCategory
        fields = ('category', )
```
Reduces the number of queries to 85.

