**nexgtv.py**
```
import re

from streamlink.plugin import Plugin
from streamlink.plugin.api import http, useragents
from streamlink.stream import HLSStream

class nexGTv(Plugin):
    _url_re = re.compile(r'https?://(?:www\.)?m.nexgtv.com/.+')

    @classmethod
    def can_handle_url(cls, url):
        return cls._url_re.match(url)

    def _get_streams(self):
        try:
            http.headers = {'User-Agent': useragents.ANDROID}
            url_content = http.get(self.url)
            http.cookies = url_content.cookies
            url_content_text = url_content.text
            authtoken = url_content_text[url_content_text.index('headers: {"authtoken": ')+24 :]
            authtoken = authtoken[: authtoken.index("'")]
            http.headers.update({'authtoken': authtoken})
            channel_id = url_content_text[url_content_text.index("getSecurePlayUrl('")+18 :]
            channel_id = channel_id[: channel_id.index("'")]
            hls_url = http.get("http://m.nexgtv.com/users/getsecureplayurl/" + channel_id).text
            hls_url = hls_url[hls_url.index('"finalUrl":"')+12 :]
            hls_url = hls_url[: hls_url.index('"')]
            hls_url = hls_url.replace("\/", "/")
            return HLSStream.parse_variant_playlist(self.session, hls_url)
        except:
            self.logger.error("The requested channel is unavailable.")

__plugin__ = nexGTv
```

